#include <functional>
#include <type_traits>
#include <memory>
#include <algorithm>
#include <vector>
#include <random>
#include <iostream>

// std::result_of устарел; используйте std::invoke_result
template<typename F, typename... Args>
using my_result_t = std::invoke_result_t<F, Args...>;

// std::is_pod устарел; используйте is_trivial && is_standard_layout
template<typename T>
constexpr bool is_pod_like = std::is_trivial_v<T> && std::is_standard_layout_v<T>;

// std::binary_function удалён; лямбды заменили его
// Было: struct Add : std::binary_function<int, int, int> { ... };
// Стало: auto add = [](int a, int b) { return a + b; };

// std::random_shuffle удалён; используйте std::shuffle
void demo_shuffle(std::vector<int>& v) {
    std::mt19937 rng(42);  // фиксированный seed для воспроизводимости
    std::shuffle(v.begin(), v.end(), rng);
}

int main() {
    // invoke_result вместо result_of
    using T = my_result_t<decltype([](int x) { return x * 2.0; }), int>;
    std::cout << "result type is double: " << std::is_same_v<T, double> << "\n";

    // is_trivial + is_standard_layout вместо is_pod
    struct Plain { int x; double y; };
    struct WithVirtual { virtual void f() {} };
    std::cout << "Plain is pod-like: " << is_pod_like<Plain> << "\n";          // 1
    std::cout << "Virtual is pod-like: " << is_pod_like<WithVirtual> << "\n";  // 0

    // std::shuffle вместо random_shuffle
    std::vector<int> v{1, 2, 3, 4, 5};
    demo_shuffle(v);
    std::cout << "shuffled: ";
    for (int x : v) std::cout << x << " ";
    std::cout << "\n";

    // allocator_traits вместо allocator::construct
    std::allocator<int> alloc;
    int* p = std::allocator_traits<std::allocator<int>>::allocate(alloc, 1);
    std::allocator_traits<std::allocator<int>>::construct(alloc, p, 42);
    std::cout << "constructed: " << *p << "\n";
    std::allocator_traits<std::allocator<int>>::destroy(alloc, p);
    std::allocator_traits<std::allocator<int>>::deallocate(alloc, p, 1);
}

#include <iostream>
#include <atomic>
#include <type_traits>
#include <iterator>

int main() {
    // Вместо volatile int для разделяемого состояния — atomic:
    std::atomic<int> counter{0};
    counter += 1;       // корректно (атомарное составное присваивание)
    counter.fetch_add(1);  // явная форма
    std::cout << "counter: " << counter.load() << "\n";

    // volatile остаётся уместен для memory-mapped I/O (аппаратные регистры)
    // Устарели только конкретные паттерны:
    // - volatile int как параметр:  void f(volatile int)  -- deprecated
    // - составные присваивания:     v += 1               -- deprecated
    // - volatile как тип возврата:  volatile int f()      -- deprecated

    // std::iterator как базовый класс устарел.
    // Было: struct MyIter : std::iterator<std::forward_iterator_tag, int> { ... };
    // Стало — объявлять типы явно:
    struct ModernIterator {
        using iterator_category = std::forward_iterator_tag;
        using value_type        = int;
        using difference_type   = std::ptrdiff_t;
        using pointer           = int*;
        using reference         = int&;
        // ... реализация
    };

    std::cout << "ModernIterator is valid: "
              << std::is_same_v<ModernIterator::value_type, int> << "\n";
}
